import sys
import itertools
import random

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return
    grid = []
    for i in range(0, 81):
        grid.append(int(input_data[i]))
    board = [grid[i*9:(i+1)*9] for i in range(9)]
    stamps = []
    for r in range(7):
        for c in range(7):
            s = 0
            for dr in range(3):
                for dc in range(3):
                    s += board[r + dr][c + dc]
            stamps.append(s)
    MOD = 998244353
    max_val = 0
    # Since 49 is too large for 2^49, use a randomized approach
    for _ in range(10000):
        current_sum = 0
        for s in stamps:
            if random.random() > 0.5:
                current_sum += s
        max_val = max(max_val, current_sum % MOD)
    print(max_val)

solve()
